const requestBody = ($json.body && typeof $json.body === 'object') ? $json.body : ($input.item.json || {});
const dryRun = Boolean($json.body && $json.body.dry_run) || Boolean(requestBody.dry_run);
const candidateIds = [...new Set((Array.isArray(requestBody.candidate_ids) ? requestBody.candidate_ids : [])
  .map((value) => Number(value))
  .filter((value) => Number.isInteger(value) && value > 0))];
const candidateNames = [...new Set((Array.isArray(requestBody.candidate_names) ? requestBody.candidate_names : [])
  .concat(typeof requestBody.candidate_name === 'string' ? [requestBody.candidate_name] : [])
  .map((value) => String(value || '').trim())
  .filter(Boolean))];
const clauses = [];
if (candidateIds.length) {
  clauses.push(`c.id IN (${candidateIds.join(', ')})`);
}
if (candidateNames.length) {
  const quotedNames = candidateNames
    .map((value) => `'${value.replace(/'/g, "''")}'`)
    .join(', ');
  clauses.push(`c.name IN (${quotedNames})`);
}
const filterClause = clauses.length ? `WHERE ${clauses.join(' OR ')}` : '';
return {
  dry_run: dryRun,
  candidate_ids: candidateIds,
  candidate_names: candidateNames,
  filter_clause: filterClause,
};

const rows = $input.all().map((item) => item.json);
const wouldChangeCount = rows.length ? Number(rows[0].would_change_count || 0) : 0;
return {
  json_response: JSON.stringify({
    ok: true,
    dryRun: true,
    scopedCount: rows.length,
    changedCount: 0,
    wouldChangeCount,
    rows,
  })
};

